old_metric = '''const getBoxMetric = (box, key, fallback = 0) => {\n  const value = Number(box?.[key]);\n  return Number.isFinite(value) ? value : fallback;\n};\n'''
new_metric = '''const getBoxMetric = (box, key, fallback = 0) => {\n  const value = Number(box?.[key]);\n  return Number.isFinite(value) ? value : fallback;\n};\n\nconst getBoxDimension = (box, compactKey, longKey, fallback = 0) => {\n  const compactValue = Number(box?.[compactKey]);\n  if (Number.isFinite(compactValue) && compactValue > 0) return compactValue;\n  const longValue = Number(box?.[longKey]);\n  return Number.isFinite(longValue) && longValue > 0 ? longValue : fallback;\n};\n'''
if old_metric not in js:
    raise SystemExit('frontend metric block not found')
js = js.replace(old_metric, new_metric)

old_highlight = '''  const updateOriginalHighlight = (wordData) => {\n    const box = getWordBox(wordData);\n    if (!imageRef.current || !originalPreviewRef.current || !box) {\n      setHighlightedBox(null);\n      return;\n    }\n\n    const image = imageRef.current;\n    if (!image.complete || image.naturalWidth === 0) {\n      setHighlightedBox(null);\n      return;\n    }\n\n    const imageRect = image.getBoundingClientRect();\n    const previewRect = originalPreviewRef.current.getBoundingClientRect();\n    const sourceWidth = getBoxMetric(box, "original_width", image.naturalWidth || imageRect.width || 1);\n    const sourceHeight = getBoxMetric(box, "original_height", image.naturalHeight || imageRect.height || 1);\n    const scaleX = imageRect.width / sourceWidth;\n    const scaleY = imageRect.height / sourceHeight;\n\n    setHighlightedBox({\n      x: (imageRect.left - previewRect.left) + originalPreviewRef.current.scrollLeft + (getBoxMetric(box, "x") * scaleX),\n      y: (imageRect.top - previewRect.top) + originalPreviewRef.current.scrollTop + (getBoxMetric(box, "y") * scaleY),\n      w: Math.max(10, getBoxMetric(box, "w") * scaleX),\n      h: Math.max(12, getBoxMetric(box, "h") * scaleY),\n    });\n  };\n'''
new_highlight = '''  const updateOriginalHighlight = (wordData) => {\n    const box = getWordBox(wordData);\n    if (!imageRef.current || !originalPreviewRef.current || !box) {\n      setHighlightedBox(null);\n      return;\n    }\n\n    const image = imageRef.current;\n    const preview = originalPreviewRef.current;\n    if (!image.complete || image.naturalWidth === 0 || image.naturalHeight === 0) {\n      setHighlightedBox(null);\n      return;\n    }\n\n    const imageRect = image.getBoundingClientRect();\n    const previewRect = preview.getBoundingClientRect();\n    const sourceWidth = getBoxDimension(box, "original_width", "source_width", image.naturalWidth || imageRect.width || 1);\n    const sourceHeight = getBoxDimension(box, "original_height", "source_height", image.naturalHeight || imageRect.height || 1);\n    const boxX = getBoxMetric(box, "x", 0);\n    const boxY = getBoxMetric(box, "y", 0);\n    const boxWidth = getBoxDimension(box, "w", "width", 1);\n    const boxHeight = getBoxDimension(box, "h", "height", 1);\n    const scaleX = imageRect.width / sourceWidth;\n    const scaleY = imageRect.height / sourceHeight;\n\n    setHighlightedBox({\n      x: (imageRect.left - previewRect.left) + preview.scrollLeft + (boxX * scaleX),\n      y: (imageRect.top - previewRect.top) + preview.scrollTop + (boxY * scaleY),\n      w: Math.max(8, boxWidth * scaleX),\n      h: Math.max(8, boxHeight * scaleY),\n    });\n  };\n'''
if old_highlight not in js:
    raise SystemExit('frontend highlight block not found')
js = js.replace(old_highlight, new_highlight)

